

const products = [
  { id: 101, name: "Laptop", price: 85000, category: "Electronics", stock: 15 },
  { id: 102, name: "Office Chair", price: 12000, category: "Furniture", stock: 0 },
  { id: 103, name: "Smart Watch", price: 5000, category: "Electronics", stock: 4 },
  { id: 104, name: "Desk Lamp", price: 1500, category: "Furniture", stock: 8 },
  { id: 105, name: "Mechanical Keyboard", price: 7000, category: "Electronics", stock: 25 },
  { id: 106, name: "Gaming Mouse", price: 3500, category: "Electronics", stock: 2 }
];

function InventoryDashboard() {
  return (
    <>
      <table border="1" cellPadding="10" cellSpacing="0">
        <thead>
          <tr>
            <th>Name</th>
            <th>Category</th>
            <th>Price</th>
            <th>Stock</th>
            <th>Availability Status</th>
          </tr>
        </thead>
        <tbody>


          {products.map((obj, index) => {

            return (
              <tr key={index} style={{
                color:
                  obj.stock === 0 ? "red" :
                    obj.stock >= 1 && obj.stock <= 10 ? "orange" :
                      obj.stock > 10 && obj.price > 50000 ? "green" : "white",

                fontStyle: obj.stock === 0 ? "italic" : "normal"
              }}>
                <td>{obj.name}</td>
                <td>{obj.category}</td>
                <td>{obj.price}</td>
                <td>{obj.stock}</td>
                <td>{obj.stock > 10 ? "In Stock" : obj.stock === 0 ? "Out of Stock" : "Limited Stock"}  </td>

              </tr>


            )


          })}
        </tbody>
      </table>
      <div className="card">
        <h3>Catalog Statistics</h3>
        <p>Total items in catalog : {products.length}</p>
        <p>{
          (products.reduce((total, product) => total + product.price, 0) / products.length).toFixed(2)}
        </p>
      </div>

      <div className="card">
        <h3>Premium Products</h3>
        {
          products.filter((product) => product.price > 10000).length > 0 ?

            (
              <ul>
                {
                  products.filter((product) => product.price > 10000).map((product) =>
                    <li key={product.id}>{product.name}</li>)
                }
              </ul>
            )
            :

            (
              <p>No premium products available at the moment.</p>
            )
        }
      </div>

      <div className="card">
        <h3>Eletronics Clearance</h3>
        <ul>
          {
            products.filter((product) => product.category === "Electronics" && product.stock < 5)
              .map((product) =>
                <li key={product.id}>{product.name} - Stock: {product.stock}</li>
              )
          }
        </ul>
      </div>
    </>

  )


}


function App() {
  return (
    <InventoryDashboard />
  )
}

export default App
